import React, { useState } from 'react';
import { useApp } from '../../App';
import { STATIONS, GARBAGE_TYPES, AREAS } from '../../data/mockData';
import { Alert } from '../../components/UI';

export default function UserPortal() {
  const { addComplaint } = useApp();
  const [stationIdx, setStationIdx] = useState(0);
  const [gtypeIdx, setGtypeIdx] = useState(0);
  const [area, setArea] = useState(AREAS[0]);
  const [desc, setDesc] = useState('');
  const [success, setSuccess] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    const stn = STATIONS[stationIdx];
    const gt = GARBAGE_TYPES[gtypeIdx];
    
    addComplaint({
      station: stn,
      gtype: gt.label,
      emoji: gt.emoji,
      severity: gt.severity,
      area,
      desc,
      lat: (stn.lat + (Math.random() - 0.5) * 0.005),
      lng: (stn.lng + (Math.random() - 0.5) * 0.005),
      reportedBy: 'Citizen Mobile App'
    });
    
    setDesc('');
    setSuccess(true);
    setTimeout(() => setSuccess(false), 4000);
  };

  return (
    <div style={{ maxWidth: 500, margin: '60px auto', padding: 20, background: '#fff', borderRadius: 16, border: '1px solid #DDE3E9', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', fontFamily: 'sans-serif' }}>
      <h2 style={{ margin: '0 0 4px 0', fontSize: 20, fontWeight: 800 }}>Report Public Waste</h2>
      <p style={{ margin: '0 0 20px 0', fontSize: 12, color: '#7A8FA6' }}>Instantly log cleaning tickets onto Indian Railways command network</p>
      
      {success && <div style={{ marginBottom: 12 }}><Alert type="green">Grievance registered in database snapshot seamlessly!</Alert></div>}
      
      <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
        <div>
          <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>RAILWAY STATION</label>
          <select value={stationIdx} onChange={e => setStationIdx(Number(e.target.value))} style={{ width: '100%', padding: 10, borderRadius: 8, border: '1px solid #DDE3E9' }}>
            {STATIONS.map((s, idx) => <option key={s.id} value={idx}>{s.name} ({s.code})</option>)}
          </select>
        </div>

        <div>
          <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>SPECIFIC STATION AREA</label>
          <select value={area} onChange={e => setArea(e.target.value)} style={{ width: '100%', padding: 10, borderRadius: 8, border: '1px solid #DDE3E9' }}>
            {AREAS.map(a => <option key={a} value={a}>{a}</option>)}
          </select>
        </div>

        <div>
          <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>WASTE CATEGORY TYPE</label>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
            {GARBAGE_TYPES.map((g, idx) => (
              <div key={g.id} onClick={() => setGtypeIdx(idx)} style={{
                padding: 10, borderRadius: 8, border: `2px solid ${gtypeIdx === idx ? '#1565C0' : '#DDE3E9'}`,
                background: gtypeIdx === idx ? '#E3F2FD' : '#fff', cursor: 'pointer', fontSize: 12.5, fontWeight: 600
              }}>{g.emoji} {g.label}</div>
            ))}
          </div>
        </div>

        <div>
          <label style={{ fontSize: 11, fontWeight: 700, color: '#546E7A', display: 'block', marginBottom: 4 }}>ADDITIONAL CONTEXT DESCRIPTION</label>
          <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={3} placeholder="Provide landmarks or notes..." style={{ width: '100%', padding: 10, borderRadius: 8, border: '1px solid #DDE3E9', fontFamily: 'sans-serif', boxSizing: 'border-box' }} />
        </div>

        <button type="submit" style={{ background: '#0A1628', color: '#fff', padding: 12, borderRadius: 8, border: 'none', fontWeight: 700, cursor: 'pointer', marginTop: 6 }}>
          🚀 File Real-Time Complaint
        </button>
      </form>
    </div>
  );
}
